-- =====================================================================
-- Base de datos: encuestas_oxxo -- SCRIPT DEFINITIVO v2
-- Reemplaza TODOS los archivos de migracion anteriores (1-9).
-- Pensado para correr sobre una base NUEVA o vacia.
-- =====================================================================

DROP DATABASE IF EXISTS encuestas_oxxo;
CREATE DATABASE encuestas_oxxo CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE encuestas_oxxo;

SET FOREIGN_KEY_CHECKS = 0;

-- ---------------------------------------------------------------------
-- ROL
-- ---------------------------------------------------------------------
CREATE TABLE rol (
  id                     INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  nombre                 VARCHAR(30)  NOT NULL UNIQUE,
  gestiona_preguntas     BOOLEAN      NOT NULL DEFAULT 0,
  gestiona_usuarios      BOOLEAN      NOT NULL DEFAULT 0,
  es_encuestable         BOOLEAN      NOT NULL DEFAULT 0,
  ve_resultados_tiendas  BOOLEAN      NOT NULL DEFAULT 0
) ENGINE=InnoDB;

-- ATI y WEBMASTER pueden gestionar preguntas (confirmado, sin cambio).

-- ---------------------------------------------------------------------
-- Jerarquia negocio -> region -> plaza (todas con su cr real)
-- ---------------------------------------------------------------------
CREATE TABLE negocio (
  id          INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  nombre      VARCHAR(100) NOT NULL,
  es_default  BOOLEAN      NOT NULL DEFAULT 0
) ENGINE=InnoDB;

CREATE TABLE region (
  id          INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  negocio_id  INT UNSIGNED NOT NULL,
  nombre      VARCHAR(100) NOT NULL,
  cr          VARCHAR(10)  NULL,
  es_default  BOOLEAN      NOT NULL DEFAULT 0,
  CONSTRAINT fk_region_negocio FOREIGN KEY (negocio_id)
    REFERENCES negocio(id) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB;

CREATE TABLE plaza (
  id          INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  region_id   INT UNSIGNED NOT NULL,
  nombre      VARCHAR(100) NOT NULL,
  cr          VARCHAR(10)  NULL,
  es_default  BOOLEAN      NOT NULL DEFAULT 0,
  CONSTRAINT fk_plaza_region FOREIGN KEY (region_id)
    REFERENCES region(id) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB;

CREATE INDEX idx_negocio_default ON negocio (es_default);
CREATE INDEX idx_region_default  ON region  (es_default);
CREATE INDEX idx_plaza_default   ON plaza   (es_default);




-- ---------------------------------------------------------------------
-- USUARIO
-- plaza_id NULL = sin restriccion (webmaster ve todo; ATI tambien
-- puede cubrir varias plazas, por eso tampoco se les fija una sola).
-- ---------------------------------------------------------------------
CREATE TABLE usuario (
  id                      INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  rol_id                  INT UNSIGNED NOT NULL,
  plaza_id                INT UNSIGNED NULL,
  correo                  VARCHAR(150) NOT NULL UNIQUE,
  nombre_completo         VARCHAR(150) NULL,
  password_hash           VARCHAR(255) NOT NULL,
  debe_cambiar_password   BOOLEAN      NOT NULL DEFAULT 0,
  foto_perfil             VARCHAR(255) NULL,
  fecha_registro          DATETIME     NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_usuario_rol FOREIGN KEY (rol_id)
    REFERENCES rol(id) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT fk_usuario_plaza FOREIGN KEY (plaza_id)
    REFERENCES plaza(id) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB;

