-- 7 asesores TI nuevos, detectados en la BDT, sin cuenta previa.
-- Password temporal (cambia en el primer login), sin foto, sin plaza fija.


-- ---------------------------------------------------------------------
-- TIENDA
-- ---------------------------------------------------------------------
CREATE TABLE tienda (
  id                    INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  plaza_id              INT UNSIGNED NOT NULL,
  codigo                VARCHAR(20)  NOT NULL,
  nombre                VARCHAR(150) NOT NULL,
  direccion             VARCHAR(255) NULL,
  latitud               DECIMAL(10,7) NULL,
  longitud              DECIMAL(10,7) NULL,
  asesor_ti_usuario_id  INT UNSIGNED NULL,
  CONSTRAINT fk_tienda_plaza FOREIGN KEY (plaza_id)
    REFERENCES plaza(id) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT fk_tienda_asesor FOREIGN KEY (asesor_ti_usuario_id)
    REFERENCES usuario(id) ON DELETE SET NULL ON UPDATE CASCADE,
  UNIQUE KEY uk_tienda_codigo (codigo)
) ENGINE=InnoDB;

CREATE INDEX idx_tienda_asesor ON tienda (asesor_ti_usuario_id);

